    MOVD R2, R14

c_loop:
    CBZ  R12, c_done
    MOVD R5, R15
    MOVD R13, R16
    MOVD R14, R17

kh_loop:
    CBZ  R15, kh_done
    MOVD R6, R19
    MOVD R16, R20
    MOVD R17, R21

kw_loop:
