    BF16_BITS_TO_F32_H4(V2.H8, V20.H8)
    VFMLA_S4(20, 1, 0)
    ADD  $2, R21
    ADD  $2, R20
    SUB  $1, R19
    B    kw_loop

kw_done:
    ADD  R7, R16, R16
    ADD  R9, R17, R17
    SUB  $1, R15
    B    kh_loop

kh_done:
    ADD  R8, R13, R13
    ADD  R10, R14, R14
    SUB  $1, R12
